            new PageContent { Id = Guid.Parse("6c2a09a2-4ef6-6695-74b0-3cc4f390e77a"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.eyebrow", ContentValue = @"Phân loại Gói", Label = @"Hero · Nhãn", Kind = @"text", SoftOrder = 148, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("3bc2c192-1ca6-6e15-a5ba-cd2d2677c0a3"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.hero.title", ContentValue = @"Ba viên ngọc, ba chuẩn dịch vụ.", Label = @"Hero · Tiêu đề", Kind = @"textarea", SoftOrder = 149, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("5f708f4b-6ee3-a579-f4b4-377a54e4a94d"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.hero.intro", ContentValue = @"Akoya, Tahiti và South Sea là ba chuẩn dịch vụ Perlunas đặt ra, gọi tên theo ba dòng ngọc trai quý nhất thế giới. Mỗi chuẩn áp dụng cho nhiều gói ở nhiều nơi và mức giá khác nhau — đây là ý nghĩa và những gì có trong từng gói.", Label = @"Hero · Đoạn mở đầu", Kind = @"textarea", SoftOrder = 150, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("3a177178-c1ea-a6a1-a2a7-34f5bc6a9ced"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.choose.eyebrow", ContentValue = @"Cách chọn gói", Label = @"Cách chọn gói · Nhãn", Kind = @"text", SoftOrder = 151, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("1793d50d-5841-876e-cdb3-9e502116d530"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.choose.title", ContentValue = @"Chọn gói phù hợp với nhu cầu của bạn.", Label = @"Cách chọn gói · Tiêu đề", Kind = @"textarea", SoftOrder = 152, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("db67b3fb-553f-fdaf-9467-876c02c6d368"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.choose.body", ContentValue = @"Mỗi gói phù hợp với một kiểu chuyến đi khác nhau — về ngân sách, mức độ riêng tư và những trải nghiệm bạn mong muốn. Phần hướng dẫn chọn gói chi tiết sẽ được Perlunas cập nhật. Trong lúc đó, cứ để lại thông tin, chúng tôi sẽ tư vấn gói hợp nhất cho bạn.", Label = @"Cách chọn gói · Nội dung", Kind = @"textarea", SoftOrder = 153, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("4833c9bf-99f2-69ab-3817-65e89697a740"), PageKey = @"Phân loại Combo", SectionKey = "", Key = @"combotiers.choose.button", ContentValue = @"Nhận tư vấn chọn gói", Label = @"Cách chọn gói · Nút", Kind = @"text", SoftOrder = 154, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
