            new PageContent { Id = Guid.Parse("9a456cc3-7974-7c70-e82a-123bf7b84c91"), PageKey = @"Chung", SectionKey = "", Key = @"footer.newsletter.eyebrow", ContentValue = @"Nhận ưu đãi và thông tin mới nhất từ Perlunas", Label = @"Footer · Newsletter nhãn", Kind = @"text", SoftOrder = 156, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("991e2f42-0f0a-e069-f763-98bc3a1eca4b"), PageKey = @"Chung", SectionKey = "", Key = @"footer.legal.tagline", ContentValue = @"Mỗi hành trình là một viên ngọc dưới ánh trăng.", Label = @"Footer · Câu cuối", Kind = @"text", SoftOrder = 157, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("ba50fe2e-7c8e-e352-71bf-cebef3c3c268"), PageKey = @"Chi tiết tour", SectionKey = "", Key = @"tourdetail.why.eyebrow", ContentValue = @"Vì sao có hành trình này", Label = @"Nhãn: Vì sao", Kind = @"text", SoftOrder = 158, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("97985a23-5eed-6f0a-79dd-832003789342"), PageKey = @"Chi tiết tour", SectionKey = "", Key = @"tourdetail.why.body", ContentValue = @"Hành trình được Perlunas thiết kế để bạn cảm nhận trọn vẹn điểm đến theo cách thong thả và chân thật nhất. Chúng tôi chọn lọc từng điểm dừng, cân nhắc nhịp đi và khoảng nghỉ để mỗi ngày đều có một khoảng thở — không nhồi nhét, không vội vã, chỉ giữ lại những trải nghiệm thật sự đáng nhớ.", Label = @"Vì sao: nội dung", Kind = @"textarea", SoftOrder = 159, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
