            new PageContent { Id = Guid.Parse("4a8b82f4-19ec-9564-7b17-d85ee6ed510b"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.meta.title", ContentValue = @"Chính sách & Điều khoản", Label = @"Policy: title", Kind = @"text", SoftOrder = 355, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("8b8b7f55-6f69-821c-2f0e-a94fc654df42"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.meta.desc", ContentValue = @"Chính sách đặt dịch vụ, thanh toán, hoàn hủy, bảo mật thông tin và điều khoản sử dụng dịch vụ của Perlunas.", Label = @"Policy: desc", Kind = @"textarea", SoftOrder = 356, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("8d18b1ed-b7a5-b610-9055-cab0a0f35a96"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.eyebrow", ContentValue = @"Pháp lý", Label = @"Policy: eyebrow", Kind = @"text", SoftOrder = 357, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("b43cd03e-6e0e-61a5-1db5-73415c7b3bd2"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.title", ContentValue = @"Chính sách & Điều khoản", Label = @"Policy: title", Kind = @"text", SoftOrder = 358, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("c2a9c70a-40cc-3f07-7c61-e3e47af071ff"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.intro", ContentValue = @"Các chính sách dưới đây áp dụng cho dịch vụ Perlunas cung cấp. Vui lòng đọc kỹ trước khi sử dụng dịch vụ.", Label = @"Policy: intro", Kind = @"textarea", SoftOrder = 359, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("fd45dbcc-e42b-4595-b7f1-051ca42535c7"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.body", ContentValue = @"<section><h2>1. Chính sách đặt dịch vụ &amp; thanh toán</h2><ul><li>Khách hàng đặt cọc trước để giữ chỗ; phần còn lại thanh toán trước ngày khởi hành theo thỏa thuận trong hợp đồng/xác nhận dịch vụ.</li><li>Các hình thức thanh toán: chuyển khoản ngân hàng, tiền mặt tại văn phòng hoặc các kênh thanh toán được Perlunas hỗ trợ.</li><li>Mọi khoản phí, thuế và dịch vụ kèm theo sẽ được thông báo rõ ràng trước khi xác nhận đặt chỗ.</li></ul></section><section><h2>2. Chính sách hoàn &amp; hủy</h2><ul><li>Yêu cầu hủy/đổi lịch cần được gửi bằng văn bản (email/Zalo) tới Perlunas.</li><li>Mức phí hoàn/hủy phụ thuộc vào thời điểm thông báo và quy định của nhà cung cấp dịch vụ (hãng bay, khách sạn, đối tác tour).</li><li>Trường hợp bất khả kháng (thiên tai, dịch bệnh…) sẽ được xử lý theo thỏa thuận và quy định của các bên liên quan.</li></ul></section><section><h2>3. Chính sách bảo mật thông tin</h2><ul><li>Perlunas thu thập thông tin khách hàng chỉ nhằm phục vụ việc tư vấn, đặt và cung cấp dịch vụ.</li><li>Thông tin cá nhân được bảo mật, không chia sẻ cho bên thứ ba ngoài mục đích thực hiện dịch vụ hoặc theo yêu cầu của pháp luật.</li></ul></section><section><h2>4. Trách nhiệm &amp; điều khoản chung</h2><ul><li>Perlunas cam kết cung cấp dịch vụ đúng như mô tả đã xác nhận với khách hàng.</li><li>Khách hàng có trách nhiệm cung cấp thông tin chính xác và tuân thủ các quy định của điểm đến, nhà cung cấp dịch vụ.</li><li>Mọi khiếu nại được tiếp nhận và xử lý qua hotline hoặc email chính thức của công ty.</li></ul></section>", Label = @"Policy: body", Kind = @"richtext", SoftOrder = 360, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
            new PageContent { Id = Guid.Parse("5c950fa8-d6e4-09cb-7721-0b59eae183b6"), PageKey = @"Chính sách & Điều khoản", SectionKey = "", Key = @"policy.contact.pre", ContentValue = @"Mọi thắc mắc về chính sách, vui lòng liên hệ", Label = @"Policy: pre", Kind = @"text", SoftOrder = 361, CreatedAt = SeedIds.CreatedAt, UpdatedAt = SeedIds.CreatedAt },
